def get_tone_prompt_block(tone: Dict) -> str:
    """
    根据基调配置生成用于 LLM prompt 的完整基调说明文本。
    接口：name, description, narrative_logic, writing_style, character_rules,
          relationship_handling, conflict_resolution, theme_orientation,
          detail_requirements, taboo_content
    """
    if not tone or not isinstance(tone, dict):
        return ""
    parts = [
        f"- 基调名称：{tone.get('name', '')}",
        f"- 基调描述：{tone.get('description', '')}",
        f"- 叙事逻辑：{tone.get('narrative_logic', '')}",
        f"- 写作风格：{tone.get('writing_style', '')}",
        f"- 角色规则：{tone.get('character_rules', '')}",
        f"- 关系处理：{tone.get('relationship_handling', '')}",
        f"- 矛盾解决：{tone.get('conflict_resolution', '')}",
        f"- 主题导向：{tone.get('theme_orientation', '')}",
        f"- 细节要求：{tone.get('detail_requirements', '')}",
        f"- 禁忌内容：{tone.get('taboo_content', '')}",
    ]
    return "\n       ".join(p for p in parts if p.split("：", 1)[-1].strip())


def get_tone_brief_for_worldview(tone: Dict) -> str:
    """
    用于世界观生成时的简短基调描述（一行内）。
    接口与 TONE_CONFIGS 一致（name, description, taboo_content 等）。
    """
    if not tone or not isinstance(tone, dict):
        return ""
    name = tone.get("name", "")
    desc = tone.get("description", "")
    taboo = tone.get("taboo_content", "")
    return f"{name}（{desc}），叙事与写作要求见完整基调；禁忌：{taboo}"


